    // Global functions for buttons
    window.generateNewTree = function() {
      playSfx('pullOut'); // old tree being pulled out, the moment the button is hit
      if (tree) {
        gsap.to(tree.mesh.position, {
          y: 200,
          duration: 1,
          ease: "power2.in",
          onComplete: () => {
            scene.remove(tree.mesh);
            createNewTree();
          }
        });
      } else {
        createNewTree();
      }
    };

    function createNewTree() {
      tree = new Tree();
      app.tree = tree;
      // A fresh tree isn't tied to any saved entry — reset the name/id so Save
      // creates a new gallery entry rather than overwriting a loaded one.
      app.newTreeIdentity?.();
      tree.mesh.position.y = 8.5;
      // Clip roots at the soil surface (= the tree base in world space).
      app.rootClipPlane.constant = -tree.mesh.position.y;
      scene.add(tree.mesh);
      tree.prewarmDebris?.(); // compile prune-offcut shaders now so the first cut is smooth

      // Animate tree growing
      tree.mesh.scale.set(0.01, 0.01, 0.01);
      playSfx('growBig', { rate: 0.8 }); // the whole tree sprouting — a slow, full grow
      gsap.to(tree.mesh.scale, {
        x: 1, y: 1, z: 1,
        duration: 2,
        ease: "back.out(1.7)"
      });
    }

    // Rebuild a tree from saved gallery data. Lives here (not in gallery.js) so
    // tree creation and the `tree`/scene singletons stay owned by one module;
    // gallery invokes it through app.createNewTreeWithData.
    function createNewTreeWithData(treeData) {
      if (tree) {
        scene.remove(tree.mesh);
      }

      // Reproduce the exact tree: same seed regenerates the identical base
      // structure (trunk/branches/roots/foliage colors), then the recorded edit
      // log replays the post-generation grow/prune/shape actions in order.
      // `parameters` were already applied by gallery.loadTree before this call.
      // Legacy saves without a seed fall back to a fresh random tree.

      // Branches are sized from the trunk dims at the moment they're created and
      // are NOT resized when the trunk is later reshaped (on purpose). So if the
      // saved tree's trunk was dragged after generation, build the base at the
      // ORIGINAL (genTrunc) dims so its branches come out the right size, let
      // replay restore each later grow's own dims, then snap the trunk back to the
      // final/display dims below — re-attaching branches without resizing, exactly
      // as the live session did. `truncHeight`/`truncThickness` are all branch size
      // depends on; curve/noise (and everything else) ride along in `parameters`.
      const finalH = parameters.truncHeight, finalT = parameters.truncThickness;
      if (treeData.genTrunc) {
        parameters.truncHeight = treeData.genTrunc.h;
        parameters.truncThickness = treeData.genTrunc.t;
      }

      tree = new Tree(treeData.seed);
      app.tree = tree;

      // Apply lean data if available (redundant once seeded — the lean is rolled
      // from the seed — but kept for legacy/seedless saves).
      if (treeData.leanData) {
        tree.leanX = treeData.leanData.leanX;
        tree.leanZ = treeData.leanData.leanZ;
        tree.curveStrength = treeData.leanData.curveStrength;
      }

      // Replay recorded edits onto the freshly seeded tree (may reshape the trunk
      // mid-replay to size each grown batch against the trunk it was grown on).
      tree.replayHistory(treeData.history);

      // Restore the final/display trunk if the build or replay left it elsewhere,
      // reshaping (re-attach, no resize) to mirror the session's end state.
      if (parameters.truncHeight !== finalH || parameters.truncThickness !== finalT) {
        parameters.truncHeight = finalH;
        parameters.truncThickness = finalT;
        tree.updateTrunkGeometry();
      }

      // Sit the loaded tree on the soil surface, same as a freshly generated
      // one — otherwise its base (and roots) sink below the soil and vanish.
      tree.mesh.position.y = 8.5;
      app.rootClipPlane.constant = -tree.mesh.position.y;
      scene.add(tree.mesh);
      tree.prewarmDebris?.(); // compile prune-offcut shaders now so the first cut is smooth

      // Animate tree loading
      tree.mesh.scale.set(0.01, 0.01, 0.01);
      gsap.to(tree.mesh.scale, {
        x: 1, y: 1, z: 1,
        duration: 1.5,
        ease: "back.out(1.7)"
      });
    }
    app.createNewTreeWithData = createNewTreeWithData;

    window.growMoreBranches = function() {
  if (tree) {
    // Sanity cap on the finer growth (sub-branches + twigs have no per-action
    // ceiling). Block before adding once we're at the limit. Counts the live
    // scene graph only — never the seeded stream — so save replay is unaffected.
    if (tree.branchCount() >= MAX_GROW_BRANCHES) {
      notify(`🌿 Max ${MAX_GROW_BRANCHES} branches reached`, 'linear-gradient(45deg, #c0392b, #e67e22)');
      return;
    }
    // 50% chance to add trunk branches, 50% chance to add main branch sub-branches.
    // The coin flip stays on Math.random (we record the RESULT, so it needn't be
    // seeded); the chosen method's geometry is seeded and so reproducible.
    const kind = Math.random() < 0.5 ? 'addBranches' : 'addSubBranches';
    tree.beginRecordedAction(); // seed this action's slot so it replays identically
    // New growth arrives bare; snow settles on it over time (no-op outside winter).
    setSnowStartsBare(true);
    try {
      if (kind === 'addBranches') {
        tree.addMoreBranches();
      } else {
        tree.addMoreSubBranches();
      }
      // Also bush out existing branches with a few new twigs each grow.
      tree.growMoreTwigs();
    } finally {
      setSnowStartsBare(false);
    }
    tree.record({ op: 'grow', kind });
    playSfx('grow');
  }
};

    // Loading-screen dismissal: fade it out once the scene has actually
    // rendered a frame, but keep it up for a brief minimum so it doesn't flash.
    const LOADER_MIN_MS = 900;
    const loaderStart = performance.now();
    let loaderDismissed = false;
    function dismissLoader() {
      if (loaderDismissed) return;
      loaderDismissed = true;
      const el = document.getElementById('loading-screen');
      if (!el) return;
      const wait = Math.max(0, LOADER_MIN_MS - (performance.now() - loaderStart));
      setTimeout(() => {
        el.classList.add('is-hidden');
        el.addEventListener('transitionend', () => el.remove(), { once: true });
        playIntroCamera(); // dolly + zoom-in as the loader fades to reveal the scene
      }, wait);
    }

    // One-shot entrance move: start pushed back with a wider lens, then ease into
    // the resting view (the position/fov set in initScene) over ~0.5s. controls.update()
    // re-reads camera.position each frame, so tweening it directly is respected;
    // orbit input is parked for the half-second so the user can't fight the move.
    const INTRO_DUR = 3.64; // seconds — entrance dolly + zoom-in
    function playIntroCamera() {
      if (!camera || !controls || typeof gsap === 'undefined') return;
      const target = controls.target;
      const endPos = camera.position.clone();
      const endFov = camera.fov;
      // Pull back along the view ray and widen the lens for the starting frame.
      camera.position.copy(target).addScaledVector(endPos.clone().sub(target), 1.68);
      camera.fov = 68;
      camera.updateProjectionMatrix();
      controls.enabled = false;
      gsap.to(camera.position, { x: endPos.x, y: endPos.y, z: endPos.z, duration: INTRO_DUR, ease: 'power2.out' });
      gsap.to(camera, {
        fov: endFov, duration: INTRO_DUR, ease: 'power2.out',
        onUpdate: () => camera.updateProjectionMatrix(),
        onComplete: () => { controls.enabled = true; },
      });
    }

    function animate() {
      requestAnimationFrame(animate);

      // Drive the foliage wind sway: one shared uniform set ticks every needle
      // and leaf material across the whole tree (see updateFoliageWind in tree.js).
      // Use performance.now() (ms since page load), NOT Date.now(): the epoch time
      // is ~1.75e9, and as a 32-bit shader float its per-frame change rounds away,
      // freezing the sway. performance.now() stays small enough to keep precision.
      updateFoliageWind(performance.now() * 0.001);

      // Autumn foliage periodically sheds a leaf that flutters to the ground.
      updateLeafFall(performance.now() * 0.001, tree);

      // Bare / Winter mode: drive the falling snow and toggle the garden frost.
      updateWinter(performance.now() * 0.001);

      // Autumn palette: dry the distant grass to brown (idempotent no-op otherwise).
      setEnvironmentAutumn(parameters.foliageColor === 'autumn');

      // Sky animations share one frame delta. Accumulators advance only while
      // their feature is active (and the stamp always advances), so toggling a
      // feature on resumes from where it froze instead of jumping forward.
      const nowS = performance.now() * 0.001;
      const dt = nowS - lastFrameS;
      lastFrameS = nowS;

      // Wild deer grazing/roaming the far meadow (no-op until a ring backdrop is up).
      updateDeer(dt);

      // Shiba pup at the house: sits on the deck, then roams (no-op until the house is up).
      updateShiba(dt);

      // Cloud Drift toggle: animate the always-present clouds.
      if (cloudsMoving && sky) {
        cloudTime += dt;
        sky.material.uniforms.time.value = cloudTime;
      }

      // Sky preset "Cycle": sweep the sun in a slow arc — rising in the east,
      // overhead at midday, setting in the west, then below the horizon for night.
      if (skyCycle && sky) {
        cycleTime += dt;
        const dayAngle = (cycleTime / SKY_CYCLE_PERIOD) * Math.PI * 2;
        const elevation = SKY_CYCLE_MAX_EL * Math.sin(dayAngle);
        const azimuthDeg = THREE.MathUtils.radToDeg(dayAngle) + 78;
        setSunElevation(elevation, azimuthDeg);
        // Dim the disc as it nears/dips below the horizon so dawn/dusk redden
        // instead of blowing out — full brightness only once well up (≥20°).
        sky.material.uniforms.sunBrightness.value = THREE.MathUtils.clamp(0.12 + elevation / 20, 0.12, 1.0);
        applySkyMood(moodForElevation(elevation)); // garden tracks the moving sun
        // Cast the key light (and its shadows) from the sun's direction so shadows
        // sweep and lengthen with it (floored above the horizon by keyLightPosFor).
        if (app.keyLight) app.keyLight.position.copy(keyLightPosFor(elevation, azimuthDeg));
      }

      // Time-of-day preset change: glide from the prior sky to the picked one over
      // a short tween (mutually exclusive with Cycle — picking a static preset
      // clears skyCycle, picking Cycle clears the tween).
      if (skyTransition && sky) {
        skyTransition.t = Math.min(1, skyTransition.t + dt / SKY_TRANSITION_DUR);
        const k = skyTransition.t * skyTransition.t * (3 - 2 * skyTransition.t); // smoothstep ease
        applySkyState(lerpSkyState(_skyStateScratch, skyTransition.from, skyTransition.to, k));
        if (skyTransition.t >= 1) skyTransition = null;
      }

      // Stars: fade the dome in as the sun sinks (full once it's at/below the
      // horizon) and let shooting stars streak only at night. One sun-height
      // factor drives both, so this tracks the night preset and the Cycle alike.
      const dayFactor = sunDayFactor();
      const nightVis = 1 - THREE.MathUtils.smoothstep(dayFactor, 0.12, 0.42);
      if (starField) {
        starField.material.opacity = nightVis * 0.9; // colors are pre-brightened; cap the additive bloom
        starField.visible = nightVis > 0.001;
      }
      updateShootingStars(scene, dt, dayFactor);

      // Night ambient effects share the starfield's night fade (nightVis); their
      // season gates are eased inside each updater so they glide in/out.
      const isWinter = parameters.leafType === 'none' || parameters.leafType === 'evergreen';
      const isAutumn = parameters.foliageColor === 'autumn';
      // Aurora: winter nights only (Bare / Winter scene).
      updateAurora(nowS, dt, nightVis, isWinter);
      // Fireflies: green-season nights only — skip winter (bare) and autumn.
      updateFireflies(nowS, dt, nightVis, !isWinter && !isAutumn);
      // Butterflies: clear summer days only — skip winter, autumn and spring (cherry
      // blossom or the Spring-Green palette), and fade with the sun + sky clearness.
      const isSpring = parameters.leafType === 'cherry' || parameters.foliageColor === 'spring';
      const cloudCover = sky ? sky.material.uniforms.cloudCoverage.value : 0;
      const clearFactor = 1 - THREE.MathUtils.smoothstep(cloudCover, 0.42, 0.55);
      updateButterflies(nowS, dt, dayFactor, clearFactor, !isWinter && !isAutumn && !isSpring);

      // Ambient wildlife: birds by day, crickets at night, silent under overcast.
      // Drive it off the live sun vector (so it tracks both static presets and the
      // Cycle); overcast is the only preset that drops the dome exposure below 1.
      if (sky) {
        const y = THREE.MathUtils.clamp(sky.material.uniforms.sunPosition.value.y, -1, 1);
        const elevationDeg = THREE.MathUtils.radToDeg(Math.asin(y));
        const overcast = sky.material.uniforms.skyExposure.value < 0.5;
        updateAmbient(elevationDeg, overcast);
      }

      controls.update();
      renderer.render(scene, camera);
      dismissLoader(); // first successful render tears down the loading screen

    }

    // Initialize the game
    init();