// gallery.js — the bonsai save/load gallery subsystem.
//
// Owns the saved-tree collection and everything around presenting it: saving
// the current tree (with a rendered thumbnail), the modal UI, load/delete,
// and toast notifications. Tree (re)creation itself stays in core/main — this
// module calls app.createNewTreeWithData() rather than constructing a Tree, so
// it never needs to import the Tree class or touch the scene graph directly.
//
// Persistence: savedTrees is mirrored to localStorage (STORAGE_KEY) on every
// mutation via persist(), and restored on startup via loadFromStorage(), so the
// gallery survives reloads. Each saved tree stores a seed + edit history so Load
// reproduces it exactly (see main.js createNewTreeWithData / Tree.replayHistory).

import * as THREE from 'three';
import { parameters, app } from './core.js';
import { syncControlsFromParameters } from './ui-controls.js';
import { playSfx } from './audio.js';

// Gallery-only state.
let savedTrees = [];
let isGalleryOpen = false;

// localStorage key for the persisted gallery (bump the suffix if the shape of
// the saved data ever changes incompatibly).
const STORAGE_KEY = 'bonsai.gallery.v1';

// Serialize the live `parameters` object to plain JSON. Everything is already a
// number/string except windDirection (a THREE.Vector3), which we flatten.
function serializeParameters() {
  return {
    ...parameters,
    windDirection: {
      x: parameters.windDirection.x,
      y: parameters.windDirection.y,
      z: parameters.windDirection.z
    }
  };
}

// Inverse of serializeParameters: rehydrate windDirection back into a Vector3 so
// downstream code (which calls Vector3 methods on it) keeps working.
function deserializeParameters(saved) {
  const out = { ...saved };
  if (saved && saved.windDirection && !saved.windDirection.isVector3) {
    const w = saved.windDirection;
    out.windDirection = new THREE.Vector3(w.x, w.y, w.z);
  }
  return out;
}

// Persist the whole gallery to localStorage. Thumbnails (base64 PNGs) dominate
// the payload, so if we blow the ~5MB quota we retry once without them rather
// than losing the save entirely.
function persist() {
  const write = (trees) =>
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ ...exportGallery(), trees }));
  try {
    write(savedTrees);
  } catch (err) {
    if (err && (err.name === 'QuotaExceededError' || err.code === 22)) {
      try {
        write(savedTrees.map(({ thumbnail, ...rest }) => rest));
        showStorageFullNotification();
      } catch (err2) {
        console.warn('Gallery could not be saved to localStorage:', err2);
      }
    } else {
      console.warn('Gallery could not be saved to localStorage:', err);
    }
  }
}

// Load any persisted gallery on startup. Tolerates missing/corrupt data.
function loadFromStorage() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;
    const data = JSON.parse(raw);
    if (data && Array.isArray(data.trees)) {
      savedTrees = data.trees;
    }
  } catch (err) {
    console.warn('Could not read saved gallery from localStorage:', err);
  }
}

