// environment.js — the zen garden the bonsai sits in.
//
// Builds and adds all the static scene dressing: the raked-sand ground
// (procedural texture + bump map), the garden border, the pot (soil, legs,
// rocks), the standing stones, and the decorative GLB pebble. createEnvironment()
// is the entry point, called once from main.js init() after the scene exists.
//
// Everything here adds to app.scene. The noise2D/perlinNoise helpers and the
// createTaperedBoxGeometry builder are used only by this module, so they live
// here rather than in core.

import * as THREE from 'three';
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';
import { app, Colors } from './core.js';
import { injectWindSway } from './foliageShader.js';
import { setDeerActive } from './deer.js';
import { setShibaActive } from './shiba.js';

const loader = new GLTFLoader();
let pot = null; // current pot group; replaced when the pot is rebuilt
let lantern = null; // GLB stone lantern; lazily loaded on first enable, then cached
let torii = null; // GLB torii gate; lazily loaded on first enable, then cached
let shortLantern = null; // GLB short stone lantern; lazily loaded, then cached
let waterCan = null; // GLB watering can; lazily loaded on first enable, then cached
let stool = null; // GLB stool; lazily loaded on first enable, then cached
let tea = null; // GLB tea set resting on the stool; lazily loaded, then cached
let bamboo = null; // GLB bamboo + moss patch in the garden corner; lazily loaded, then cached
let house = null; // GLB house backdrop sitting just beyond the garden; lazily loaded, then cached

// The stool's seat in the garden, shared by setStoolVisible and setTeaVisible so
// the tea set always lands on the stool. STOOL_TOP_Y is the sand level (-29) plus
// the scaled height, since the stool is seated base-on-sand at exactly that height.
const STOOL_POS = { x: -24, z: 58 }; // close to the bonsai, front-left
const STOOL_HEIGHT = 26; // world units; a low accent on the sand
const STOOL_TOP_Y = -29 + STOOL_HEIGHT;
let gravel = null; // zen-garden gravel plane; tinted by the Darker Gravel toggle
let gravelDark = false; // settings toggle: tint the gravel a darker gray
let zenRocksGroup = null; // the standing garden rocks; frosted in winter mode
let sceneSnow = null; // lazily-built group of snow caps on the pot + rocks
let _snowOn = false; // current winter frost state (idempotent toggle guard)
let _autumnOn = false; // current autumn-grass state (idempotent toggle guard)
let groundShader = null; // distant grass disc's compiled shader, for the winter/autumn uniforms

// ── Rock surface normals ──────────────────────────────────────────────────────
// Shares the settings drawer's "Surface Textures" checkbox with the bark normals
// (bark.js owns the bark side; settings.js drives both from the one toggle). Rocks
// are built once in createEnvironment, so each rock material registers itself and
// which normal it wants; setRockTexture applies or clears them all. Loaded lazily
// and cached, in linear space (NoColorSpace) like the bark normals.
const _rockNormalLoader = new THREE.TextureLoader();
const _rockNormals = {};
let _rockTextureEnabled = false;
const _rockMaterials = []; // { material, file } registered at build time

function getRockNormal(file) {
  if (_rockNormals[file]) return _rockNormals[file];
  const tex = _rockNormalLoader.load(`assets/textures/${file}`);
  tex.colorSpace = THREE.NoColorSpace;
  tex.wrapS = THREE.RepeatWrapping;
  tex.wrapT = THREE.RepeatWrapping;
  _rockNormals[file] = tex;
  return tex;
}

// Register a rock material + its normal file, applying it now if textures are on.
function registerRock(material, file) {
  _rockMaterials.push({ material, file });
  if (_rockTextureEnabled) {
    material.normalMap = getRockNormal(file);
    material.needsUpdate = true;
  }
}

// Settings-drawer toggle (paired with bark): apply or clear the rock normals across
// every registered rock material. Only hits the loader when enabling, so the rock
// normal jpgs aren't fetched until the texture toggle is first switched on.
export function setRockTexture(enabled) {
  _rockTextureEnabled = !!enabled;
  for (const { material, file } of _rockMaterials) {
    material.normalMap = enabled ? getRockNormal(file) : null;
    material.needsUpdate = true;
  }
}

// Builds the distant mountain-ring backdrop and returns the mesh (does not add
// it to the scene). Toggled on demand via setMountainsVisible().
function buildMountainRing() {
  const radius = 1826;
  const baseHeight = 180;
  const segments = 148;

  const mountainGeo = new THREE.CylinderGeometry(
    radius, radius, baseHeight, segments, 16, true
  );

  const pos = mountainGeo.attributes.position;
  const vertex = new THREE.Vector3();
  const displacementScale = 250;
  const radialScale = 120;

  // === Shape mountains ===
  for (let i = 0; i < pos.count; i++) {
    vertex.fromBufferAttribute(pos, i);

    if (vertex.y > 0) {
      const angle = Math.atan2(vertex.z, vertex.x);
      const noise = (Math.sin(angle * 5) * 0.5 + 0.5) * Math.random();

      vertex.y += noise * displacementScale;

      const dir = new THREE.Vector2(vertex.x, vertex.z).normalize();
      vertex.x += dir.x * noise * radialScale;
      vertex.z += dir.y * noise * radialScale;

      pos.setXYZ(i, vertex.x, vertex.y, vertex.z);
    }
  }
  mountainGeo.computeVertexNormals();

  // === Colors (simple vertical gradient) ===
  const colors = [];
  const snowAmt = []; // per-vertex snow coverage, ramped in on the upper slopes for winter mode
  const color1 = new THREE.Color(0x36454F); // base
  const color2 = new THREE.Color(0x708090); // mid
  const color3 = new THREE.Color(0xC0C0C0); // peaks

  // Find min & max height after displacement
  let minY = Infinity, maxY = -Infinity;
  for (let i = 0; i < pos.count; i++) {
    vertex.fromBufferAttribute(pos, i);
    if (vertex.y < minY) minY = vertex.y;
    if (vertex.y > maxY) maxY = vertex.y;
  }

  for (let i = 0; i < pos.count; i++) {
    vertex.fromBufferAttribute(pos, i);
    const heightRatio = (vertex.y - minY) / (maxY - minY);

    let mountainColor = new THREE.Color();
    if (heightRatio < 0.65) {
      mountainColor.lerpColors(color1, color2, heightRatio / 0.65);
    } else {
      mountainColor.lerpColors(color2, color3, (heightRatio - 0.65) / 0.35);
    }

    colors.push(mountainColor.r, mountainColor.g, mountainColor.b);
    snowAmt.push(THREE.MathUtils.smoothstep(heightRatio, 0.78, 0.94)); // high snowline → just the peaks cap
  }
  mountainGeo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  mountainGeo.setAttribute('aSnow', new THREE.Float32BufferAttribute(snowAmt, 1));

  // === Material ===
  const mountainMat = new THREE.MeshStandardMaterial({
    vertexColors: true,
    flatShading: true,
    side: THREE.BackSide
  });
  // Winter: blend the upper slopes/peaks toward snow-white. uWinter is flipped by
  // setEnvironmentSnow(); the per-vertex aSnow ramp keeps the lower slopes bare.
  mountainMat.onBeforeCompile = (shader) => {
    shader.uniforms.uWinter = { value: _snowOn ? 1 : 0 };
    mountainMat.userData.shader = shader;
    shader.vertexShader = shader.vertexShader
      .replace('void main() {', 'attribute float aSnow;\nvarying float vSnow;\nvoid main() {')
      .replace('#include <begin_vertex>', '#include <begin_vertex>\n  vSnow = aSnow;');
    shader.fragmentShader = shader.fragmentShader
      .replace('void main() {', 'uniform float uWinter;\nvarying float vSnow;\nvoid main() {')
      .replace(
        '#include <color_fragment>',
        '#include <color_fragment>\n  float snowCap = clamp(uWinter * vSnow, 0.0, 1.0);\n  diffuseColor.rgb = mix(diffuseColor.rgb, vec3(1.0), snowCap);'
      )
      // Self-lit lift on the caps so the distant fog doesn't wash the white away.
      .replace(
        '#include <emissivemap_fragment>',
        '#include <emissivemap_fragment>\n  totalEmissiveRadiance += vec3(0.55, 0.58, 0.62) * snowCap;'
      );
  };

  const mountainRing = new THREE.Mesh(mountainGeo, mountainMat);
  mountainRing.position.y = -38;
  return mountainRing;
}

// Builds the lone Mt-Fuji cone — a single snow-capped peak set further out than
// the mountain ring so it rises behind the range. Returns the mesh (not added to
// the scene); toggled via setFujiVisible(). Like the ring it carries an aSnow
// ramp + uWinter shader so winter blankets it lower, but its upper cap is baked
// in so the signature snow cap shows in every season.
function buildFujiMountain() {
  // The cone runs far taller/wider than what reads above the horizon: only the
  // top ~760 units are the "visible" peak (see VIS_SPAN below); the rest of the
  // skirt plunges deep below the horizon so its base never shows as a hard edge —
  // it just dissolves into the distance/fog. Visible slope ≈ the old 760→96 cone.
  const topRadius = 94;   // flattened summit (the crater plateau), not a sharp point
  const height = 1400;
  const radial = 140;     // dense enough for the fine snowline fringe to resolve
  const rings = 52;

  // --- Fuji silhouette: radius as a function of distance *below the summit* ---
  // Two slopes joined by a smooth bend give the signature concave sweep — a gentle
  // upper cone, then a shallower, wider-flaring skirt. Keyed to depth-below-summit
  // (not the full cone height) so the curve sits in the visible peak, not the
  // buried lower geometry. The skirt keeps widening down to baseRadius in the fog.
  const summitY = height / 2;
  const KNEE = 300;         // depth below summit where the curve sits (~mid visible peak)
  const R_MID = 480;        // radius at the knee
  const UPPER_SLOPE = (R_MID - topRadius) / KNEE; // gentle upper cone (≈38° from horizontal)
  const LOWER_SLOPE = 1.7;  // shallower angle → wider flared base (concave skirt)
  const baseRadius = R_MID + LOWER_SLOPE * (height - KNEE); // ≈ 2350, far below horizon

  // Capped truncated cone: a small top radius gives Fuji's signature flat summit.
  const fujiGeo = new THREE.CylinderGeometry(topRadius, baseRadius, height, radial, rings, false);
  const pos = fujiGeo.attributes.position;
  const vertex = new THREE.Vector3();

  // Reshape the straight frustum to the two-slope profile above; a touch of
  // low-freq noise (faded out near the clean summit) softens the silhouette.
  for (let i = 0; i < pos.count; i++) {
    vertex.fromBufferAttribute(pos, i);
    const d = summitY - vertex.y; // 0 at summit → height at base
    const r = Math.hypot(vertex.x, vertex.z);
    if (r > 1e-3) { // skip the flat cap centers so the plateau stays flat
      const angle = Math.atan2(vertex.z, vertex.x);
      const rUpper = topRadius + UPPER_SLOPE * d;
      const rLower = R_MID + LOWER_SLOPE * (d - KNEE);
      const bend = THREE.MathUtils.smoothstep(d, KNEE - 170, KNEE + 170); // the gentle curve
      const fade = THREE.MathUtils.clamp(d / 380, 0, 1); // calm the noise near the summit
      const wobble = 1 + (Math.sin(angle * 7) * 0.5 + Math.sin(angle * 3 + 1.7)) * 0.018 * fade;
      const radius = THREE.MathUtils.lerp(rUpper, rLower, bend) * wobble;
      vertex.x = Math.cos(angle) * radius;
      vertex.z = Math.sin(angle) * radius;
      pos.setXYZ(i, vertex.x, vertex.y, vertex.z);
    }
  }
  fujiGeo.computeVertexNormals();

  // === Colors: hazy slate-blue slopes → white summit cap ===
  // Ramps are keyed to distance *below the summit* (VIS_SPAN), not the full cone
  // height, so the cap stays a cap no matter how far the skirt extends down. hv:
  // 1 at the summit → 0 once VIS_SPAN below it (everything deeper is plain slate).
  const colors = [];
  const snowAmt = [];
  const base = new THREE.Color(0x4a5a72);  // skirt (distance-blued slate)
  const mid = new THREE.Color(0x6a7a92);   // upper slope
  const cap = new THREE.Color(0xffffff);   // permanent snow cap
  const VIS_SPAN = 760;  // how far down from the summit the gradient/cap spans
  const SNOWLINE = 0.58; // (in hv) baked cap starts here → top ~165 units

  for (let i = 0; i < pos.count; i++) {
    vertex.fromBufferAttribute(pos, i);
    const hv = THREE.MathUtils.clamp(1 - (summitY - vertex.y) / VIS_SPAN, 0, 1);
    const c = new THREE.Color();
    if (hv < SNOWLINE) {
      c.lerpColors(base, mid, hv / SNOWLINE);
    } else {
      // Snowline edge: layered high frequencies at small amplitude read as a
      // fine, irregular fringe (snow fingers running down gullies) rather than
      // the big regular scallops a single low-freq wave gives (cartoonish).
      const angle = Math.atan2(vertex.z, vertex.x);
      const fringe = Math.sin(angle * 29) * 0.5
                   + Math.sin(angle * 61 + 1.3) * 0.3
                   + Math.sin(angle * 17 + 0.6) * 0.2;
      const edge = SNOWLINE + fringe * 0.014;
      const t = THREE.MathUtils.smoothstep(hv, edge, edge + 0.1);
      c.lerpColors(mid, cap, t);
    }
    colors.push(c.r, c.g, c.b);
    // Winter pushes the snow further down the skirt.
    snowAmt.push(THREE.MathUtils.smoothstep(hv, 0.45, 0.74));
  }
  fujiGeo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  fujiGeo.setAttribute('aSnow', new THREE.Float32BufferAttribute(snowAmt, 1));

  const fujiMat = new THREE.MeshStandardMaterial({
    vertexColors: true,
    flatShading: true,
    side: THREE.DoubleSide,
  });
  // Same winter recipe as the mountain ring: uWinter blends the lower slopes
  // toward snow-white, gated per-vertex by aSnow.
  fujiMat.onBeforeCompile = (shader) => {
    shader.uniforms.uWinter = { value: _snowOn ? 1 : 0 };
    fujiMat.userData.shader = shader;
    shader.vertexShader = shader.vertexShader
      .replace('void main() {', 'attribute float aSnow;\nvarying float vSnow;\nvoid main() {')
      .replace('#include <begin_vertex>', '#include <begin_vertex>\n  vSnow = aSnow;');
    shader.fragmentShader = shader.fragmentShader
      .replace('void main() {', 'uniform float uWinter;\nvarying float vSnow;\nvoid main() {')
      .replace(
        '#include <color_fragment>',
        '#include <color_fragment>\n  float snowCap = clamp(uWinter * vSnow, 0.0, 1.0);\n  diffuseColor.rgb = mix(diffuseColor.rgb, vec3(1.0), snowCap);'
      )
      .replace(
        '#include <emissivemap_fragment>',
        '#include <emissivemap_fragment>\n  totalEmissiveRadiance += vec3(0.55, 0.58, 0.62) * snowCap;'
      );
  };

  const fuji = new THREE.Mesh(fujiGeo, fujiMat);
  // Set further out than the ring (radius 1826) so it sits behind the range. The
  // summit lands at +485 world (clearing the ring's ~+300 silhouette) while the
  // long skirt runs down to ≈ -1000, far below the horizon, dissolving into fog.
  const azimuth = -2.1; // radians; tucked behind, off-axis from the default view
  const dist = 2280;
  const peakY = 485;
  fuji.position.set(Math.cos(azimuth) * dist, peakY - height / 2, Math.sin(azimuth) * dist);
  return fuji;
}

///
// ZEN GARDEN
///
function createZenGardenTexture() {
  const textureSize = 1024;
  const canvas = document.createElement('canvas');
  canvas.width = textureSize;
  canvas.height = textureSize;
  const ctx = canvas.getContext('2d');
  
  // Fill with base sand color first
  ctx.fillStyle = '#E6D5C3';
  ctx.fillRect(0, 0, textureSize, textureSize);
  
  // Create image data for procedural generation
  const imageData = ctx.createImageData(textureSize, textureSize);
  const data = imageData.data;
  
  // Define ripple positions (matching your zen garden rocks)
  const rockPositions = [
    { x: 0.2, y: 0.4, radius: 0.12 },  // Increased radius for more visible ripples
    { x: 0.18, y: 0.45, radius: 0.10 },
    { x: 0.35, y: 0.7, radius: 0.11 },
    { x: 0.85, y: 0.8, radius: 0.13 },
    { x: 0.75, y: 0.85, radius: 0.12 },
    // { x: 0.5, y: 0.5, radius: 0.12 }
  ];
  
  // Generate zen garden sand patterns
  for (let x = 0; x < textureSize; x++) {
    for (let y = 0; y < textureSize; y++) {
      const index = (y * textureSize + x) * 4;
      
      // Normalize coordinates to 0-1 range
      const nx = x / textureSize;
      const ny = y / textureSize;
      
      // Base sand color
      let r = 230, g = 213, b = 195; // #E6D5C3 in RGB
      
      // Check if we're near a rock for circular ripples
      let rippleIntensity = 0;
      
      for (const rock of rockPositions) {
        const dx = nx - rock.x;
        const dy = ny - rock.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        
        if (distance < rock.radius * 2.5) { // Extended ripple area
          // Create concentric ripples
          const rippleDistance = distance / (rock.radius * 2.5);
          const rippleFrequency = 22; // Adjusted for better visibility
          
          // Main ripple pattern - stronger amplitude
          const mainRipple = Math.sin(rippleDistance * Math.PI * rippleFrequency) * 0.6;
          
          // Secondary ripples for complexity
          const secondaryRipple = Math.sin(rippleDistance * Math.PI * rippleFrequency * 1.3) * 0.3;
          
          // Fade ripples toward edge
          const edgeFade = Math.pow(1 - rippleDistance, 1.5);
          
          rippleIntensity = Math.max(rippleIntensity, (mainRipple + secondaryRipple) * edgeFade);
        }
      }
      
      // If not near rocks, create flowing ripples
      if (rippleIntensity === 0) {
        // Horizontal flowing ripples
        const horizontalRipple = Math.sin(ny * Math.PI * 22) * 0.4;
        
        // Diagonal ripples
        const diagonalRipple = Math.sin((nx * 0.7 + ny * 0.7) * Math.PI * 15) * 0.2;
        
        // Vary intensity across the surface
        const flowIntensity = 0.3 + 0.7 * Math.sin(nx * Math.PI * 3) * Math.sin(ny * Math.PI * 2);
        
        rippleIntensity = (horizontalRipple) * flowIntensity;
      }
      
      // Apply ripple effect to color
      const rippleEffect = rippleIntensity * 60; // Increased for visibility
      
      r = Math.max(0, Math.min(255, r + rippleEffect));
      g = Math.max(0, Math.min(255, g + rippleEffect));
      b = Math.max(0, Math.min(255, b + rippleEffect));
      
      // Add subtle sand grain texture
      const grain = (noise2D(nx * 80, ny * 80) - 0.5) * 15;
      r = Math.max(0, Math.min(255, r + grain));
      g = Math.max(0, Math.min(255, g + grain));
      b = Math.max(0, Math.min(255, b + grain));
      
      data[index] = r;     // Red
      data[index + 1] = g; // Green
      data[index + 2] = b; // Blue
      data[index + 3] = 255; // Alpha
    }
  }
  
  ctx.putImageData(imageData, 0, 0);
  
  // Create texture from canvas
  const sandTexture = new THREE.CanvasTexture(canvas);
  sandTexture.wrapS = THREE.RepeatWrapping;
  sandTexture.wrapT = THREE.RepeatWrapping;
  sandTexture.repeat.set(1, 1); // Reduced to show more detail
  sandTexture.needsUpdate = true;
  
  return sandTexture;
}

// Create a separate bump map specifically for zen garden ripples
function createZenGardenBumpMap() {
  const bumpSize = 1024;
  const canvas = document.createElement('canvas');
  canvas.width = bumpSize;
  canvas.height = bumpSize;
  const ctx = canvas.getContext('2d');
  
  const imageData = ctx.createImageData(bumpSize, bumpSize);
  const data = imageData.data;
  
  // Same rock positions
  const rockPositions = [
    { x: 0.2, y: 0.4, radius: 0.12 },
    { x: 0.18, y: 0.45, radius: 0.10 },
    { x: 0.35, y: 0.7, radius: 0.11 },
    { x: 0.85, y: 0.8, radius: 0.13 },
    { x: 0.75, y: 0.85, radius: 0.12 }
  ];
  
  for (let x = 0; x < bumpSize; x++) {
    for (let y = 0; y < bumpSize; y++) {
      const index = (y * bumpSize + x) * 4;
      const nx = x / bumpSize;
      const ny = y / bumpSize;
      
      let height = 128; // Middle gray = neutral height
      
      // Add ripple height variations
      let rippleHeight = 0;
      
      for (const rock of rockPositions) {
        const dx = nx - rock.x;
        const dy = ny - rock.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        
        if (distance < rock.radius * 2.5) {
          const rippleDistance = distance / (rock.radius * 2.5);
          const rippleFrequency = 12;
          
          const mainRipple = Math.sin(rippleDistance * Math.PI * rippleFrequency) * 0.8;
          const edgeFade = Math.pow(1 - rippleDistance, 1.5);
          
          rippleHeight = Math.max(rippleHeight, mainRipple * edgeFade);
        }
      }
      
      if (rippleHeight === 0) {
        const horizontalRipple = Math.sin(ny * Math.PI * 28) * 0.4;
       // const diagonalRipple = Math.sin((nx * 0.7 + ny * 0.7) * Math.PI * 15) * 0.3;
        const flowIntensity = 0.3 + 0.7 * Math.sin(nx * Math.PI * 3) * Math.sin(ny * Math.PI * 2);
        
        rippleHeight = (horizontalRipple) * flowIntensity;
      }
      
      height += rippleHeight * 80; // Strong height variation
      height = Math.max(0, Math.min(255, height));
      
      data[index] = height;
      data[index + 1] = height;
      data[index + 2] = height;
      data[index + 3] = 255;
    }
  }
  
  ctx.putImageData(imageData, 0, 0);
  
  const bumpTexture = new THREE.CanvasTexture(canvas);
  bumpTexture.wrapS = THREE.RepeatWrapping;
  bumpTexture.wrapT = THREE.RepeatWrapping;
  bumpTexture.repeat.set(1, 1);
  bumpTexture.needsUpdate = true;
  
  return bumpTexture;
}

// stone border
function createZenGardenBorder() {
  const borderGroup = new THREE.Group();
  
  // Border dimensions
  const borderWidth = 900; // Width of zen garden area
  const borderDepth = 980; // Depth of zen garden area
  const wallHeight = 8; // Height above ground
  const wallThickness = 12; // Thickness of walls
  const postHeight = 16; // Corner posts height
  const postSize = 10; // Corner post dimensions
  
  // Stone material for border
  const stoneMaterial = new THREE.MeshStandardMaterial({
    color: 0x6B6B6B, // Gray stone color
    roughness: 0.9,
    metalness: 0.1,
    flatShading: true
  });
  
  // Create the four border walls with gaps for visual interest
  
  // NORTH WALL (back) - with center gap
  const northWall1 = createBorderSection(borderWidth * 0.35, wallHeight, wallThickness);
  northWall1.position.set(-borderWidth * 0.325, wallHeight/2 - 29, borderDepth/2);
  borderGroup.add(northWall1);
  
  const northWall2 = createBorderSection(borderWidth * 0.35, wallHeight, wallThickness);
  northWall2.position.set(borderWidth * 0.325, wallHeight/2 - 29, borderDepth/2);
  borderGroup.add(northWall2);
  
  // SOUTH WALL (front) - with two gaps
  const southWall1 = createBorderSection(borderWidth * 0.25, wallHeight, wallThickness);
  southWall1.position.set(-borderWidth * 0.375, wallHeight/2 - 29, -borderDepth/2);
  borderGroup.add(southWall1);
  
  const southWall2 = createBorderSection(borderWidth * 0.3, wallHeight, wallThickness);
  southWall2.position.set(0, wallHeight/2 - 29, -borderDepth/2);
  borderGroup.add(southWall2);
  
  const southWall3 = createBorderSection(borderWidth * 0.25, wallHeight, wallThickness);
  southWall3.position.set(borderWidth * 0.375, wallHeight/2 - 29, -borderDepth/2);
  borderGroup.add(southWall3);
  
  // EAST WALL (right) - with small gap
  const eastWall1 = createBorderSection(wallThickness, wallHeight, borderDepth * 0.4);
  eastWall1.position.set(borderWidth/2, wallHeight/2 - 29, -borderDepth * 0.3);
  borderGroup.add(eastWall1);
  
  const eastWall2 = createBorderSection(wallThickness, wallHeight, borderDepth * 0.4);
  eastWall2.position.set(borderWidth/2, wallHeight/2 - 29, borderDepth * 0.3);
  borderGroup.add(eastWall2);
  
  // WEST WALL (left) - continuous
  const westWall = createBorderSection(wallThickness, wallHeight, borderDepth);
  westWall.position.set(-borderWidth/2, wallHeight/2 - 29, 0);
  borderGroup.add(westWall);
  
  // Create corner posts
  const cornerPositions = [
    [-borderWidth/2, -borderDepth/2], // Southwest
    [borderWidth/2, -borderDepth/2],  // Southeast  
    [borderWidth/2, borderDepth/2],   // Northeast
    [-borderWidth/2, borderDepth/2]   // Northwest
  ];
  
  cornerPositions.forEach((pos, index) => {
    const post = createCornerPost(postSize, postHeight);
    post.position.set(pos[0], postHeight/2 - 29, pos[1]);
    borderGroup.add(post);
  });
  
  // Add some decorative mid-wall posts
  const midPost1 = createCornerPost(postSize * 0.8, postHeight * 0.8);
  midPost1.position.set(0, postHeight * 0.4 - 29, borderDepth/2);
  borderGroup.add(midPost1);
  
  const midPost2 = createCornerPost(postSize * 0.8, postHeight * 0.8);
  midPost2.position.set(borderWidth/2, postHeight * 0.4 - 29, 0);
  borderGroup.add(midPost2);
  
  app.scene.add(borderGroup);
}

// Helper function to create a border wall section
function createBorderSection(width, height, depth) {
  const sectionGroup = new THREE.Group();
  
  // Create main wall geometry with slight taper for natural look
  const wallGeometry = new THREE.BoxGeometry(width, height, depth, 3, 2, 2);
  
  // Add some irregularity to make it look hand-built
  const positions = wallGeometry.attributes.position;
  for (let i = 0; i < positions.count; i++) {
    const x = positions.getX(i);
    const y = positions.getY(i);
    const z = positions.getZ(i);
    
    // Add slight random displacement, more at the top
    const heightFactor = (y + height/2) / height; // 0 at bottom, 1 at top
    const displacement = (Math.random() - 0.5) * 0.8 * heightFactor;
    
    positions.setX(i, x + displacement);
    positions.setZ(i, z + displacement * 0.5);
  }
  wallGeometry.computeVertexNormals();
  
  // Stone material with color variation
  const stoneMaterial = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.1, 0.1, 0.45 + Math.random() * 0.1), // Slight color variation
    roughness: 0.9,
    metalness: 0.1,
    flatShading: true
  });
  
  const wall = new THREE.Mesh(wallGeometry, stoneMaterial);
  wall.castShadow = true;
  wall.receiveShadow = true;
  
  sectionGroup.add(wall);
  return sectionGroup;
}

// Helper function to create corner posts
function createCornerPost(size, height) {
  const postGroup = new THREE.Group();
  
  // Create post with octagonal cross-section for more interesting shape
  const postGeometry = new THREE.CylinderGeometry(
    size * 0.9, // Top radius (slightly smaller)
    size,       // Bottom radius
    height,     // Height
    8,          // Radial segments (octagonal)
    2           // Height segments
  );
  
  // Add weathering details to posts
  const positions = postGeometry.attributes.position;
  for (let i = 0; i < positions.count; i++) {
    const x = positions.getX(i);
    const y = positions.getY(i);
    const z = positions.getZ(i);
    
    // Add subtle surface irregularities
    const noise = (Math.random() - 0.5) * 0.5;
    const radius = Math.sqrt(x * x + z * z);
    const factor = radius > 0 ? noise / radius : 0;
    
    positions.setX(i, x + x * factor);
    positions.setZ(i, z + z * factor);
  }
  postGeometry.computeVertexNormals();
  
  // Slightly darker stone for posts
  const postMaterial = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.1, 0.15, 0.4 + Math.random() * 0.08),
    roughness: 0.95,
    metalness: 0.05,
    flatShading: true
  });
  
  const post = new THREE.Mesh(postGeometry, postMaterial);
  post.castShadow = true;
  post.receiveShadow = true;
  
  postGroup.add(post);
  
  return postGroup;
}

// distant trees
// --- Simple Perlin noise generator (value noise fallback if you don't want an external lib) ---
function perlinNoise(x) {
  return (
    Math.sin(x * 0.25) * 0.5 +
    Math.sin(x * 0.7) * 0.25 +
    Math.sin(x * 2.3) * 0.15
  );
}

// Builds the distant forest-ring backdrop (a band of treetops that sits just
// inside the mountain ring) and returns the mesh. Toggled via setForestVisible().
function buildForestRing() {
  const radius = 1760;          // inside mountain ring
  const baseHeight = 12;        // baseline tree height
  const segments = 312;         // higher resolution = smoother curve

  const positions = [];
  const colors = [];
  const snowAmt = []; // 0 at the trunk line, 1 at the crowns → snow gathers on the treetops in winter

  const colorBottom = new THREE.Color(0x123a1d); // deep green (kept dark so fog doesn't wash it out)
  const colorTop = new THREE.Color(0x27713f);    // mid green
  // Autumn palette (same as the leaves) — sampled per-fragment as confetti, below.
  const fall = Colors.autumn.map(h => new THREE.Color(h));

  for (let i = 0; i <= segments; i++) {
    const angle = (i / segments) * Math.PI * 2;
    const x = Math.cos(angle) * radius;
    const z = Math.sin(angle) * radius;

    // Multi-octave noise for leafy crown shape
    const lowFreq = perlinNoise(i * 0.1) * 20;   // big treetop waves
    const midFreq = perlinNoise(i * 0.4) * 12;   // tree clumps
    const highFreq = perlinNoise(i * 1.5) * 6;   // leaf detail

    const treetop = baseHeight + lowFreq + midFreq + highFreq * 6.8;
    // Add base + top vertices
    positions.push(x, -38, z);         // bottom (flat line)
    positions.push(x, treetop, z);   // top (leafy silhouette)

    // Colors: bottom dark, top lighter
    const bottomColor = colorBottom.clone();
    colors.push(bottomColor.r, bottomColor.g, bottomColor.b);
    snowAmt.push(0); // bottom (trunk line) — no snow

    const topColor = new THREE.Color().lerpColors(colorBottom, colorTop, 0.7);
    colors.push(topColor.r, topColor.g, topColor.b);
    snowAmt.push(1); // crown — snow gathers here
  }

  // Build geometry as triangle strip
  const geo = new THREE.BufferGeometry();
  geo.setAttribute("position", new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute("color", new THREE.Float32BufferAttribute(colors, 3));
  geo.setAttribute("aSnow", new THREE.Float32BufferAttribute(snowAmt, 1));

  const indices = [];
  for (let i = 0; i < segments * 2; i += 2) {
    indices.push(i, i + 1, i + 2);
    indices.push(i + 1, i + 3, i + 2);
  }
  geo.setIndex(indices);
  geo.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    vertexColors: true,
    side: THREE.DoubleSide,
    flatShading: true
  });
  // Autumn recolors the foliage to the leaf palette as world-space *confetti* —
  // sampled per fragment from a cellular hash so the colors speckle freely across
  // the whole band (a far-off blur of mixed trees), decoupled from the vertex grid
  // so there's no vertical/horizontal banding. Winter then gathers snow on the
  // treetops (pow() biases the white to the crowns; a self-lit lift carries it
  // through the fog, mirroring the mountain caps). uAutumn / uWinter are flipped
  // by setEnvironmentAutumn / setEnvironmentSnow.
  mat.onBeforeCompile = (shader) => {
    shader.uniforms.uWinter = { value: _snowOn ? 1 : 0 };
    shader.uniforms.uAutumn = { value: _autumnOn ? 1 : 0 };
    shader.uniforms.uFall = { value: fall }; // vec3[5], the autumn palette
    mat.userData.shader = shader;
    shader.vertexShader = shader.vertexShader
      .replace('void main() {', 'attribute float aSnow;\nvarying float vSnow;\nvarying vec3 vWorldPos;\nvoid main() {')
      .replace('#include <begin_vertex>', '#include <begin_vertex>\n  vSnow = aSnow;\n  vWorldPos = (modelMatrix * vec4(transformed, 1.0)).xyz;');
    shader.fragmentShader = shader.fragmentShader
      .replace(
        'void main() {',
        `uniform float uWinter;
        uniform float uAutumn;
        uniform vec3 uFall[5];
        varying float vSnow;
        varying vec3 vWorldPos;
        float fHash(vec3 p){ return fract(sin(dot(p, vec3(127.1, 311.7, 74.7))) * 43758.5453); }
        // Smooth 3D value noise (trilinear, smoothstep) — continuous so neighbouring
        // fragments land on similar values, grouping alike colors into soft regions.
        float vNoise(vec3 p){
          vec3 i = floor(p), f = fract(p);
          f = f * f * (3.0 - 2.0 * f);
          float n000 = fHash(i), n100 = fHash(i + vec3(1.0, 0.0, 0.0));
          float n010 = fHash(i + vec3(0.0, 1.0, 0.0)), n110 = fHash(i + vec3(1.0, 1.0, 0.0));
          float n001 = fHash(i + vec3(0.0, 0.0, 1.0)), n101 = fHash(i + vec3(1.0, 0.0, 1.0));
          float n011 = fHash(i + vec3(0.0, 1.0, 1.0)), n111 = fHash(i + vec3(1.0, 1.0, 1.0));
          return mix(
            mix(mix(n000, n100, f.x), mix(n010, n110, f.x), f.y),
            mix(mix(n001, n101, f.x), mix(n011, n111, f.x), f.y),
            f.z);
        }
        void main() {`
      )
      .replace(
        '#include <color_fragment>',
        `#include <color_fragment>
        if (uAutumn > 0.0) {
          // Smooth color field instead of hard cells: a broad region noise groups
          // alike colors into drifts, a finer octave breaks them up, and we blend
          // between the two neighbouring palette entries (no hard floor/ceil) so the
          // flecks melt into each other.
          vec3 wp = vWorldPos;
          float field = vNoise(wp * 0.013) * 0.72 + vNoise(wp * 0.11) * 0.28;
          float t = clamp(field, 0.0, 1.0) * 3.9999;   // 0..(N-1) palette coordinate
          int lo = int(floor(t));
          float fr = t - float(lo);
          vec3 cLo = uFall[0], cHi = uFall[0];
          for (int k = 0; k < 5; k++) {
            if (k == lo) cLo = uFall[k];
            if (k == lo + 1) cHi = uFall[k];
          }
          vec3 confetti = mix(cLo, cHi, fr);            // soft blend between neighbours
          confetti *= 0.82 + 0.28 * vNoise(wp * 0.18 + 19.3); // gentle brightness drift
          diffuseColor.rgb = mix(diffuseColor.rgb, confetti, uAutumn);
        }
        float snowCap = clamp(uWinter * pow(vSnow, 3.0), 0.0, 1.0);
        diffuseColor.rgb = mix(diffuseColor.rgb, vec3(1.0), snowCap);`
      )
      .replace(
        '#include <emissivemap_fragment>',
        '#include <emissivemap_fragment>\n  totalEmissiveRadiance += vec3(0.45, 0.48, 0.52) * snowCap;'
      );
  };

  const treeRing = new THREE.Mesh(geo, mat);
  treeRing.position.y = -10;
  return treeRing;
}

