// Distant pagoda backdrop: a GLB landmark set far out so it reads as part of the
// horizon, not the garden. Unlike the mountain/forest rings it stands on its own
// and does NOT pull up the distant ground disc — it can sit against the bare sky.
// It's a loaded model rather than generated geometry, so the group is added
// immediately and the mesh dropped in when the async load resolves.
function setPagodaVisible(visible) {
  if (visible && !app.backdrops.pagoda) {
    const group = new THREE.Group();
    app.backdrops.pagoda = group;
    app.scene.add(group);
    loader.load('assets/models/Pagoda.glb', function (gltf) {
      const model = gltf.scene;
      // Measure the real bounding box and scale to a target height, then seat it
      // on the ground — robust to whatever units/transforms the GLB ships with.
      const targetHeight = 280; // tall enough to read across the distance
      const size = new THREE.Vector3();
      new THREE.Box3().setFromObject(model).getSize(size);
      model.scale.setScalar(targetHeight / size.y);

      const scaledBox = new THREE.Box3().setFromObject(model);
      // Far off toward the back-left, well beyond the garden, inside the rings.
      model.position.set(-900, -30 - scaledBox.min.y, 1200);
      model.rotation.y = Math.PI * 0.85; // angle its face back toward the garden
      model.traverse(function (child) {
        if (child.isMesh) {
          child.castShadow = true;
          child.receiveShadow = true;
        }
      });
      group.add(model);
    });
  }
  if (app.backdrops.pagoda) app.backdrops.pagoda.visible = visible;
}

// Courtyard backdrop: a full enclosure (walls, pillars, roof, garden floor) that
// wraps AROUND the bonsai, with the camera living inside it. Unlike the other
// backdrops it isn't a distant accent — it's scaled to a large interior footprint
// so the camera (orbits up to maxDistance ~500 from the target) stays within the
// walls, then centered on the tree and seated on the ground. Its GLB materials
// are already double-sided, so the interior faces render correctly from inside.
function setCourtyardVisible(visible) {
  if (visible && !app.backdrops.courtyard) {
    const group = new THREE.Group();
    app.backdrops.courtyard = group;
    app.scene.add(group);
    loader.load('assets/models/courtyard.glb', function (gltf) {
      const model = gltf.scene;
      // Scale by horizontal footprint (not height): the interior must clear the
      // camera's orbit radius. 1700 wide → ~850 half-extent, well past the 500 max.
      const targetFootprint = 1330;
      const box = new THREE.Box3().setFromObject(model);
      const size = new THREE.Vector3();
      box.getSize(size);
      model.scale.setScalar(targetFootprint / Math.max(size.x, size.z));

      // Re-measure, then center the enclosure on the tree (origin) and rest its
      // floor on the ground plane (y = -30).
      const scaledBox = new THREE.Box3().setFromObject(model);
      const center = new THREE.Vector3();
      scaledBox.getCenter(center);
      model.position.set(-center.x, -30 - scaledBox.min.y, -center.z);

      model.traverse(function (child) {
        if (child.isMesh) {
          child.castShadow = true;
          child.receiveShadow = true;
        }
      });
      group.add(model);
    });
  }
  if (app.backdrops.courtyard) app.backdrops.courtyard.visible = visible;
}

