      const targetHeight = 365; // world units; a dwelling taller than the bonsai
      const size = new THREE.Vector3();
      new THREE.Box3().setFromObject(model).getSize(size);
      model.scale.setScalar(targetHeight / size.y);

      // Re-measure after scaling to drop its base onto the ground (y = -30). Set
